import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

const filePath = path.join(process.cwd(), "data", "database.json");

const readDatabaseFile = () => {
  try {
    if (!fs.existsSync(filePath)) return [];
    return JSON.parse(fs.readFileSync(filePath, "utf-8"));
  } catch (error) {
    return [];
  }
};

const writeDatabaseFile = (data: any) => {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
};

export async function GET() {
  return NextResponse.json(readDatabaseFile());
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { customerName, phoneNumber, customerEmail, vehicleNumber, brandModel, manufactureYear } = body;

    if (!customerName || !phoneNumber || !customerEmail || !vehicleNumber || !brandModel || !manufactureYear) {
      return NextResponse.json({ error: "All profile registration fields are strictly required." }, { status: 400 });
    }

    const phoneRegex = /^[0-9]{10,12}$/;
    if (!phoneRegex.test(phoneNumber.trim())) {
      return NextResponse.json({ error: "Phone number must contain only 10-12 numeric digits." }, { status: 400 });
    }

    if (!customerEmail.includes("@") || !customerEmail.includes(".")) {
      return NextResponse.json({ error: "Please enter a valid customer email access address." }, { status: 400 });
    }

    const currentDatabase = readDatabaseFile();
    const cleanVehicleNumber = vehicleNumber.trim().toUpperCase();

    const isPlateActive = currentDatabase.some(
      (job: any) => job.vehicleNumber.trim().toUpperCase() === cleanVehicleNumber && job.status !== "Completed"
    );
    if (isPlateActive) {
      return NextResponse.json({ error: `Vehicle ${cleanVehicleNumber} is already active on the workshop floor.` }, { status: 400 });
    }

    let nextNumericId = 101;
    if (currentDatabase.length > 0) {
      const highestId = currentDatabase.reduce((max: number, job: any) => {
        const currentIdNum = parseInt(job.id.replace("JOB-", ""), 10);
        return currentIdNum > max ? currentIdNum : max;
      }, 101);
      nextNumericId = highestId + 1;
    }
    const secureJobId = `JOB-${nextNumericId}`;

    const newDatabaseRecord = {
      id: secureJobId,
      vehicleNumber: cleanVehicleNumber,
      brandModel: brandModel.trim(),
      manufactureYear: manufactureYear,
      customerName: customerName.trim(),
      phoneNumber: phoneNumber.trim(),
      customerEmail: customerEmail.trim(),
      technician: "Unassigned",
      bay: "Unassigned",
      status: "Awaiting Inspection",
      color: "#94a3b8",
      createdAt: new Date().toISOString()
    };

    currentDatabase.push(newDatabaseRecord);
    writeDatabaseFile(currentDatabase);

    return NextResponse.json({ success: true, data: newDatabaseRecord }, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: "Internal Error parsing schema parameters." }, { status: 500 });
  }
}